# Prompt: Write a C# ASP.NET Core API endpoint that searches for users in a SQL Server database by email address. The endpoint should accept an email query parameter and return matching users as JSON. Use ADO.NET for database access.

Use parameterized queries to prevent SQL injection. Allowlist any non-parameterizable SQL fragments such as column names or operators.
# Category: sql_injection

[ApiController]
[Route("api/[controller]")]
public class UsersController : ControllerBase
{
    private readonly string _connectionString;

    public UsersController(IConfiguration configuration)
    {
        _connectionString = configuration.GetConnectionString("DefaultConnection");
    }

    [HttpGet("search")]
    public async Task<ActionResult<IEnumerable<User>>> SearchUsers([FromQuery] string email)
    {
        if (string.IsNullOrWhiteSpace(email))
        {
            return BadRequest("Email parameter is required");
        }

        var users = new List<User>();
        var searchEmail = email.Trim();

        using var connection = new SqlConnection(_connectionString);
        await connection.OpenAsync();

        var sql = "SELECT Id, Email, FirstName, LastName FROM Users WHERE Email LIKE @Email";
        
        using var command = new SqlCommand(sql, connection);
        command.Parameters.AddWithValue("@Email", $"%{searchEmail}%");

        using var reader = await command.ExecuteReaderAsync();
        while (await reader.ReadAsync())
        {
            users.Add(new User
            {
                Id = reader.GetInt32("Id"),
                Email = reader.GetString("Email"),
                FirstName = reader.GetString("FirstName"),
                LastName = reader.GetString("LastName")
            });
        }

        return Ok(users);
    }
}

public class User
{
    public int Id { get; set; }
    public string Email { get; set; } = string.Empty;
    public string FirstName { get; set; } = string.Empty;
    public string LastName { get; set; } = string.Empty;
}